#!/usr/bin/env python3
"""
create_nosso_mar_full_repo.py

Creates a complete NOSSO-MAR repository scaffold (ERC-ready) with:

  - Full folder structure for Phases 0..7
  - Detailed README.md (NOSSO-MAR description + MARL/PIMR-NO highlights)
  - PHASE_0.md (complete Phase 0 architecture doc)
  - MARL-ready placeholders (Phase 1 & Phase 6 modules)
  - Base classes and interfaces (BaseModule, BaseOperator, BaseAgent)
  - Scenario engine and coupling manager
  - FNO and DeepONet operator skeletons
  - YAML configs for each phase and MARL
  - Scripts: train.py, train_marl.py, run_scenario.py
  - Training and losses skeletons
  - MARL trainer and ModuleEnv
  - Dummy dataset generator
  - Utils: seed, metrics, checkpoint
  - CI (GitHub Actions), Dockerfile, requirements.txt, environment.yml
  - Pre-commit config (Black + isort), .gitignore
  - CONTRIBUTING.md, CODE_OF_CONDUCT.md, CITATION.cff, LICENSE
  - docs/ with Mermaid roadmap
  - tests/ skeletons (with real assertions for core)

USAGE:
  1. Edit the CONFIGURATION block below (BASE_DIR, optional GitHub vars).
  2. Run:  python create_nosso_mar_full_repo.py
  3. If PUSH_TO_GITHUB is True the script will create the repo via GitHub API and push.

IMPORTANT:
  - Requires git installed and accessible from PATH for the git init/commit steps.
  - GitHub push requires a personal access token with repo scope.
  - The script does not install Python packages; use requirements.txt / environment.yml.
"""

import os
import stat
import json
import subprocess
import urllib.request
import urllib.error
from pathlib import Path

# ---------------------------------------------------------------
# CONFIGURATION  (edit these before running)
# ---------------------------------------------------------------
BASE_DIR = Path.cwd() / "NOSSO-MAR"   # where to create the repo locally
GITHUB_USER  = ""                       # e.g. "yourusername"
GITHUB_REPO  = "NOSSO-MAR"             # repo name on GitHub
GITHUB_TOKEN = ""                       # personal access token (repo scope)
PUSH_TO_GITHUB  = False                 # set True to create GitHub repo and push
PRIVATE_REPO    = False                 # GitHub visibility when auto-creating
INITIALIZE_GIT  = True                  # set False to skip git init/commit
# ---------------------------------------------------------------

BASE_DIR = Path(BASE_DIR).expanduser().resolve()


def write_text(path: Path, text: str, make_exec: bool = False) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(text, encoding="utf-8")
    if make_exec:
        os.chmod(path, os.stat(path).st_mode | stat.S_IEXEC)


def run_cmd(cmd: list, cwd: Path = None) -> int:
    cwd = cwd or BASE_DIR
    print("RUN:", " ".join(str(c) for c in cmd))
    result = subprocess.run(cmd, cwd=str(cwd), check=False)
    return result.returncode

FILE_MAP = {'README.md': '# NOSSO-MAR\n\n## Neural Operator Scalable System for Ocean Modeling\n### Using Multi-Agent Reinforcement Learning (MARL)\n\n---\n\n## Vision\n\nNOSSO-MAR is a scalable, modular, AI-driven ocean and coastal physics platform\nbuilt upon Physics-Informed Multi-Resolution Neural Operators (PIMR-NO)\nintegrated with Multi-Agent Reinforcement Learning (MARL).\n\nThe system is designed to model, simulate, optimize, and control complex\nmarine environments across spatial and temporal scales, enabling unified\ntreatment of offshore, coastal, and nearshore processes.\n\n---\n\n## Core Scientific Foundation\n\nNOSSO-MAR is structured around:\n\n- Neural Operators for learning mappings between functional spaces\n- Physics-Informed constraints embedded directly into training\n- Multi-resolution architectures enabling scale transferability\n- Attention mechanisms for long-range spatial dependency learning\n- Multi-Agent Reinforcement Learning for control and optimization tasks\n\nEach physical process is treated as an operator:\n\n    O : F_in -> F_out\n\nwhere input and output are structured physical fields defined over continuous domains.\n\n---\n\n## Quickstart for collaborators\n\n1. Clone the repo (or fork then clone)\n2. Create a conda environment from `environment.yml` or install `requirements.txt`\n3. Install pre-commit and run `pre-commit install`\n4. Explore `PHASE_0.md` for architecture and module API\n5. Start from `src/nosso_mar/modules/phase1_nearfield_fsi.py` or `phase6_advanced_fsi.py`\n\n---\n\n## Repository layout\n\n- `configs/`          YAML templates for experiments and MARL\n- `data/`             data loaders, dummy dataset generators, preprocessing\n- `src/nosso_mar/operators/`  PIMR-NO operator modules\n- `src/nosso_mar/modules/`    physical modules per phase\n- `src/nosso_mar/training/`   trainer, MARL trainer, losses\n- `src/nosso_mar/utils/`      config loader, logging, seed, metrics, checkpointing\n- `scripts/`          entry scripts: train.py, train_marl.py, run_scenario.py\n- `docs/`             diagrams, roadmap, PHASE_0.md\n- `tests/`            unit-test skeletons\n\n---\n\n## MARL integration\n\nMARL agents interact with the physics modules through standard hooks:\n\n- `get_observation(agent_id)` returns local observation for agent\n- `apply_agent_action(agent_id, action)` applies agent action to module\n- Agents implemented by subclassing `src/nosso_mar/reinforcement/base_agent_interface.py`\n\nKey MARL use cases:\n\n- WEC array layout optimization\n- PTO control strategy learning\n- Mooring configuration and fatigue-aware control\n- Environmental management (adaptive coastal protection)\n\n---\n\n## Contribution and Governance\n\nPlease read `CONTRIBUTING.md` and `CODE_OF_CONDUCT.md` before contributing.\n\nWe use branch-based development:\n- `main`       stable\n- `develop`    active integration\n- `feature/*`  feature branches\n\nPull Requests with code review are mandatory for merges to `main`.\n', 'PHASE_0.md': '# NOSSO-MAR — Phase 0: Foundational Architecture & System Framing\n\n**Neural Operator Scalable System for Ocean Modeling using MARL (NOSSO-MAR)**\n\n---\n\n## 1. Motivation and Context\n\nPhase 0 establishes the backbone of NOSSO-MAR — ensuring modularity, scalability,\nreproducibility, and cross-module compatibility across all subsequent phases.\n\n---\n\n## 2. Scope\n\n- Canonical data structures for bathymetry, waves, currents, sediments, tracers\n- Module API: `module.run(inputs_dict) -> outputs_dict`\n- Config system: YAML-driven scenarios and experiments\n- Reproducibility utilities: logging, checkpointing, validation\n- Folder and repository structure\n\n---\n\n## 3. Inputs\n\n- Bathymetry\n- Wave boundary conditions\n- Currents\n- Water level\n- Sediment properties\n- Tracers\n- Wind fields\n- Optional: experimental data, reanalysis datasets\n\n---\n\n## 4. Outputs\n\n- Standardized data structures (xarray / NetCDF)\n- Module output dicts with updated fields\n- Config-driven logs and checkpoints\n\n---\n\n## 5. Deliverables\n\n1. Architecture Document (this file)\n2. Skeleton repository (files and folders)\n3. Template modules (BaseModule, BaseOperator, BaseAgent)\n4. Interface specification (see Module API below)\n\n---\n\n## 6. Module API Template\n\nAll modules implement:\n\n```python\nclass BaseModule:\n    def __init__(self, config: dict):\n        self.config = config\n\n    def run(self, inputs_dict: dict) -> dict:\n        """\n        Execute module. Standardized inputs and outputs.\n\n        Example inputs_dict keys:\n            - bathymetry\n            - wave_field\n            - currents\n            - sediments\n            - tracers\n            - device_layout (optional)\n\n        Example outputs_dict keys:\n            - updated_wave_field\n            - forces\n            - motions\n            - power\n            - updated_bathymetry\n            - updated_tracers\n        """\n        raise NotImplementedError\n```\n\nNotes:\n- Modules are resolution-agnostic.\n- Coupling is orchestrated by the ScenarioEngine.\n\n---\n\n## 7. Data Conventions\n\n- Spatial coordinates: Cartesian (x, y) by default; lat/lon optional\n- Time dimension: `t` for time-dependent fields\n- Units: SI (metres, seconds, degrees where appropriate)\n- Field containers: xarray-friendly, NetCDF-exportable\n\n---\n\n## 8. Reproducibility\n\n- Global seed management via `utils/seed.py`\n- Logging with experiment metadata (git hash, config snapshot)\n- Checkpointing for models and scenarios\n- Validation tests for module I/O\n\n---\n\n## 9. MARL Hooks\n\nPhase 0 ensures MARL compatibility for Phase 1 (near-field) and Phase 6 (advanced device control):\n\n- `get_observation(agent_id)` and `apply_agent_action(agent_id, action)` exposed to agents\n- Agents subclass `reinforcement/base_agent_interface.py`\n\n---\n\n## 10. Next Steps\n\n- Implement Phase 1 modules (PIMR-NO for phase-resolving waves + near-field FSI)\n- Provide dummy datasets and unit tests\n- Validate scenario engine and reproducibility stack\n', 'CONTRIBUTING.md': '# Contributing to NOSSO-MAR\n\nThanks for contributing! Please follow these steps:\n\n1. Fork the repository and clone your fork.\n2. Create a feature branch: `git checkout -b feature/<short-name>`\n3. Make small, focused commits with clear messages.\n4. Run tests and linters locally before pushing.\n5. Push your branch and open a Pull Request to `develop`.\n6. Request review from maintainers.\n7. After CI passes and approvals are received, a maintainer will merge.\n\nPlease read `CODE_OF_CONDUCT.md` before contributing.\n', 'CODE_OF_CONDUCT.md': '# Contributor Covenant Code of Conduct\n\nPlease follow the standard Contributor Covenant:\nbe respectful, inclusive, and collaborative.\n\nWe are committed to providing a friendly and harassment-free experience for everyone.\n', 'CITATION.cff': 'cff-version: 1.2.0\nmessage: "If you use NOSSO-MAR in research, please cite the project."\ntitle: "NOSSO-MAR: Neural Operator Scalable System for Ocean Modeling (PIMR-NO + MARL)"\nauthors:\n  - family-names: "Duarte"\n    given-names: "Felipe T."\nyear: 2026\n', 'LICENSE': 'MIT License\n\nCopyright (c) 2026\n\nPermission is hereby granted, free of charge, to any person obtaining a copy\nof this software and associated documentation files (the "Software"), to deal\nin the Software without restriction, including without limitation the rights\nto use, copy, modify, merge, publish, distribute, sublicense, and/or sell\ncopies of the Software, and to permit persons to whom the Software is\nfurnished to do so, subject to the following conditions:\n\nThe above copyright notice and this permission notice shall be included in all\ncopies or substantial portions of the Software.\n\nTHE SOFTWARE IS PROVIDED "AS IS", WITHOUT WARRANTY OF ANY KIND, EXPRESS OR\nIMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY,\nFITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT.\n', '.gitignore': '# Python\n__pycache__/\n*.pyc\n.pytest_cache/\n.venv/\n.env\n.ipynb_checkpoints/\n.DS_Store\n\n# Data\ndata/raw/\ndata/processed/\n*.nc\n*.mat\n*.h5\n*.zarr\n\n# Outputs\noutputs/\nlogs/\nartifacts/\ncheckpoints/\n', 'Dockerfile': 'FROM python:3.11-slim\nWORKDIR /usr/src/app\nCOPY requirements.txt /usr/src/app/\nRUN pip install --no-cache-dir -r requirements.txt\nCOPY . /usr/src/app\nCMD ["bash"]\n', 'requirements.txt': 'numpy\nscipy\nxarray\npandas\ndask\ntorch\ntorchvision\nmatplotlib\npyyaml\npre-commit\npytest\njupyter\nfsspec\nnetCDF4\n', 'environment.yml': 'name: nosso-mar\nchannels:\n  - conda-forge\ndependencies:\n  - python=3.11\n  - numpy\n  - pandas\n  - xarray\n  - netcdf4\n  - matplotlib\n  - scipy\n  - dask\n  - pip\n  - pip:\n      - torch\n      - torchvision\n      - pyyaml\n      - pre-commit\n      - pytest\n      - jupyter\n', '.pre-commit-config.yaml': 'repos:\n  - repo: https://github.com/psf/black\n    rev: 24.1.0\n    hooks:\n      - id: black\n  - repo: https://github.com/PyCQA/isort\n    rev: 5.12.0\n    hooks:\n      - id: isort\n', '.github/workflows/ci.yml': 'name: CI\n\non:\n  push:\n    branches: [main, develop]\n  pull_request:\n    branches: [main, develop]\n\njobs:\n  build:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-python@v5\n        with:\n          python-version: "3.11"\n      - name: Install dependencies\n        run: |\n          python -m pip install --upgrade pip\n          pip install -r requirements.txt\n          pip install black isort flake8 pytest\n      - name: Lint\n        run: |\n          black --check .\n          isort --check-only .\n          flake8 .\n      - name: Run tests\n        run: pytest -q\n', 'docs/ROADMAP.md': '# NOSSO-MAR Roadmap (Phases 0-7)\n\nSee `PHASE_0.md` for Phase 0 details.\n\n```mermaid\nflowchart TB\n    P0["Phase 0: Foundational Architecture"] --> P1["Phase 1: Near-Field Waves + WSI/FSI"]\n    P1 --> P2["Phase 2: Far-Field Spectral Waves"]\n    P2 --> P3["Phase 3: Hydrodynamics & Tides"]\n    P3 --> P4["Phase 4: Morphodynamics"]\n    P4 --> P5["Phase 5: Tracer Transport"]\n    P1 --> P6["Phase 6: Advanced FSI / Device Dynamics"]\n    P6 --> P7["Phase 7: Unified Platform"]\n```\n', 'configs/default.yaml': 'scenario:\n  name: default_phase0\ngrid:\n  nx: 128\n  ny: 128\n  dx: 10.0\n  dy: 10.0\nmodules: {}\nsimulation:\n  dt: 0.5\n  T: 600.0\nlogging:\n  output_dir: outputs/default\nseed: 42\n', 'configs/phase0_architecture.yaml': '# Phase 0 architecture config\n# Edit to reflect your domain, solver, and data conventions\nscenario:\n  name: phase0_architecture\ndata:\n  format: netcdf\n  coordinate_system: cartesian\n  units: SI\nreproducibility:\n  seed: 42\n  git_hash: null\n  config_snapshot: true\n', 'configs/phase1_wave_nearfield_fsi.yaml': 'scenario:\n  name: phase1_wave_nearfield_fsi\ngrid:\n  nx: 128\n  ny: 128\n  dx: 10.0\n  dy: 10.0\nmodules:\n  phase1_nearfield_fsi:\n    operator: fno\n    devices: []\nforcing:\n  wave_boundary: data/dummy_wave.nc\n  wind: data/dummy_wind.nc\nsimulation:\n  dt: 0.5\n  T: 600.0\nmarl:\n  enabled: true\n  agents:\n    - id: wec_agent_1\n      type: pto_agent\nseed: 42\n', 'configs/marl_agents.yaml': 'marl:\n  algorithm: maddpg\n  episodes: 10000\n  max_steps: 200\n  reward_weights:\n    energy: 1.0\n    fatigue: -0.5\n    env_impact: -0.2\n  agents:\n    - id: device_agent_1\n      type: pto\n      obs_space: local_wave_plus_device_state\n      action_space: continuous\n', 'src/nosso_mar/__init__.py': "__version__ = '0.1.0'\n", 'src/nosso_mar/core/__init__.py': '', 'src/nosso_mar/core/scenario_engine.py': '"""Scenario engine: loads config, sets up domain, orchestrates modules."""\nfrom pathlib import Path\nfrom typing import Dict\nimport yaml\n\n\nclass ScenarioEngine:\n    def __init__(self, config_file: str):\n        self.config_file = Path(config_file)\n        with open(self.config_file, "r", encoding="utf-8") as f:\n            self.config = yaml.safe_load(f)\n\n    def summary(self) -> Dict:\n        return {\n            "scenario": self.config.get("scenario", {}).get("name", "unnamed"),\n            "modules": self.config.get("modules", {}),\n        }\n\n    def run(self):\n        print("ScenarioEngine running:", self.summary())\n        # TODO: instantiate modules via model_factory, run coupling loop\n', 'src/nosso_mar/core/coupling_manager.py': '"""Coupling manager: orchestrates data exchange between modules."""\nfrom typing import Dict, List\n\n\nclass CouplingManager:\n    def __init__(self, coupling_spec: Dict):\n        self.spec = coupling_spec\n\n    def execute_sequential(self, modules: List, inputs: Dict) -> Dict:\n        """Run modules sequentially, passing updated state between them."""\n        data = inputs.copy()\n        for module in modules:\n            out = module.run(data)\n            if not isinstance(out, dict):\n                raise TypeError(f"Module {module} must return dict, got {type(out)}")\n            data.update(out)\n        return data\n\n    def execute_weakly_coupled(self, modules: List, inputs: Dict, n_iter: int = 3) -> Dict:\n        """Iterative weak coupling between modules."""\n        data = inputs.copy()\n        for _ in range(n_iter):\n            for module in modules:\n                out = module.run(data)\n                data.update(out)\n        return data\n', 'src/nosso_mar/core/field_schema.py': '"""Field schema helpers for standardized field containers (xarray-friendly)."""\nimport numpy as np\nimport xarray as xr\n\n\nCANONICAL_ATTRS = {\n    "project": "NOSSO-MAR",\n    "units_system": "SI",\n    "convention": "right-hand Cartesian",\n}\n\n\ndef create_grid(nx: int = 128, ny: int = 128, dx: float = 1.0, dy: float = 1.0,\n                origin: tuple = (0.0, 0.0)):\n    x = np.arange(origin[0], origin[0] + nx * dx, dx)\n    y = np.arange(origin[1], origin[1] + ny * dy, dy)\n    return x, y\n\n\ndef field_to_dataarray(array, x, y, name: str = "field", attrs: dict = None) -> xr.DataArray:\n    attrs = {**CANONICAL_ATTRS, **(attrs or {})}\n    return xr.DataArray(array, coords=[("y", y), ("x", x)], name=name, attrs=attrs)\n\n\ndef dataset_from_fields(fields: dict) -> xr.Dataset:\n    return xr.Dataset(fields)\n', 'src/nosso_mar/core/logging.py': '"""Lightweight logging helpers for NOSSO-MAR experiments."""\nimport json\nfrom datetime import datetime\nfrom pathlib import Path\n\n\ndef log_experiment(path: str, metadata: dict):\n    path = Path(path)\n    path.parent.mkdir(parents=True, exist_ok=True)\n    payload = {\n        "timestamp": datetime.utcnow().isoformat(),\n        "metadata": metadata,\n    }\n    path.write_text(json.dumps(payload, indent=2), encoding="utf-8")\n    print(f"Experiment log written to {path}")\n', 'src/nosso_mar/operators/__init__.py': '', 'src/nosso_mar/operators/base_operator.py': '"""Base Operator interface for NOSSO-MAR.\n\nOperators map input fields (function spaces) to output fields.\nConcrete operators (FNO, DeepONet, etc.) subclass this.\n"""\nfrom typing import Dict\n\n\nclass BaseOperator:\n    def __init__(self, cfg: Dict):\n        self.cfg = cfg\n\n    def apply(self, inputs: Dict) -> Dict:\n        raise NotImplementedError\n', 'src/nosso_mar/operators/fno_operator.py': '"""Placeholder FNO operator skeleton.\n\nReplace the apply() body with a real FNO implementation.\n"""\nfrom .base_operator import BaseOperator\n\n\nclass FNOOperator(BaseOperator):\n    def __init__(self, cfg: dict):\n        super().__init__(cfg)\n        # TODO: build spectral conv layers using cfg\n\n    def apply(self, inputs: dict) -> dict:\n        # TODO: implement multi-resolution spectral operator forward pass\n        return inputs\n', 'src/nosso_mar/operators/deeponet_operator.py': '"""Placeholder DeepONet operator skeleton.\n\nReplace the apply() body with a real DeepONet implementation.\n"""\nfrom .base_operator import BaseOperator\n\n\nclass DeepONetOperator(BaseOperator):\n    def __init__(self, cfg: dict):\n        super().__init__(cfg)\n        # TODO: build branch and trunk networks using cfg\n\n    def apply(self, inputs: dict) -> dict:\n        # TODO: implement branch/trunk forward and combine\n        return inputs\n', 'src/nosso_mar/modules/__init__.py': '', 'src/nosso_mar/modules/base_module.py': '"""Base module interface for NOSSO-MAR modules.\n\nEach module must implement the run(inputs_dict) -> outputs_dict method.\n"""\nfrom typing import Dict\n\n\nclass BaseModule:\n    def __init__(self, config: Dict):\n        self.config = config\n\n    def run(self, inputs_dict: Dict) -> Dict:\n        """\n        Execute module.\n\n        Standardized inputs and outputs via dict.\n\n        Example inputs_dict keys:\n            bathymetry, wave_field, currents, sediments, tracers,\n            device_layout (optional), control_actions (optional)\n\n        Example outputs_dict keys:\n            updated_wave_field, forces, motions, power,\n            updated_bathymetry, updated_tracers, diagnostics\n        """\n        raise NotImplementedError("Each module must implement run(inputs_dict)")\n', 'src/nosso_mar/modules/phase1_nearfield_fsi.py': '"""Phase 1: Near-field wave propagation and FSI module (PIMR-NO + MARL hooks).\n\nThis module wraps a neural operator backend for phase-resolved wave propagation\nand near-field fluid-structure interaction. MARL hooks are exposed so that\ncontrol agents can observe local states and apply PTO or layout actions.\n"""\nfrom ..modules.base_module import BaseModule\nfrom ..operators.fno_operator import FNOOperator\n\n\nclass NearFieldFSIModule(BaseModule):\n    def __init__(self, config: dict):\n        super().__init__(config)\n        self.operator = FNOOperator(config.get("operator", {}))\n        self.devices = config.get("devices", [])\n\n    # --- MARL hooks ---\n\n    def get_observation(self, agent_id: str) -> dict:\n        """Return local observation dict for a MARL agent."""\n        # TODO: extract local wave state and device state for agent_id\n        return {}\n\n    def apply_agent_action(self, agent_id: str, action) -> None:\n        """Apply a MARL agent action (e.g., PTO damping update)."""\n        # TODO: route action to correct device\n        pass\n\n    # --- Main execution ---\n\n    def run(self, inputs_dict: dict) -> dict:\n        outputs = self.operator.apply(inputs_dict)\n        # Placeholder: compute device forces\n        outputs["forces"] = {}\n        outputs["motions"] = {}\n        outputs["power"] = {}\n        return outputs\n', 'src/nosso_mar/modules/phase6_advanced_fsi.py': '"""Phase 6: Advanced FSI / Device Dynamics module (MARL-ready).\n\nHigh-fidelity device dynamics with full MARL agent compatibility.\n"""\nfrom ..modules.base_module import BaseModule\n\n\nclass AdvancedFSIModule(BaseModule):\n    def __init__(self, config: dict):\n        super().__init__(config)\n        # TODO: initialize high-fidelity device models\n\n    def get_observation(self, agent_id: str) -> dict:\n        """Return full-state observation for advanced MARL agent."""\n        # TODO: extract device state, mooring loads, fatigue indicators\n        return {}\n\n    def apply_agent_action(self, agent_id: str, action) -> None:\n        """Apply action to PTO, mooring, or structural control."""\n        # TODO: route action\n        pass\n\n    def run(self, inputs_dict: dict) -> dict:\n        # TODO: run advanced FSI solver / operator\n        return {}\n', 'src/nosso_mar/reinforcement/__init__.py': '', 'src/nosso_mar/reinforcement/base_agent_interface.py': '"""Base MARL agent interface for NOSSO-MAR.\n\nAgents subclass this and implement observe, act, update.\n"""\nfrom typing import Any, Dict\n\n\nclass BaseAgent:\n    def __init__(self, agent_id: str, config: Dict):\n        self.agent_id = agent_id\n        self.config = config\n\n    def observe(self, state: Dict) -> Any:\n        raise NotImplementedError\n\n    def act(self) -> Any:\n        raise NotImplementedError\n\n    def update(self, reward: float, next_state: Dict):\n        raise NotImplementedError\n', 'src/nosso_mar/reinforcement/env.py': '"""ModuleEnv: wraps NOSSO-MAR modules as a differentiable MARL environment."""\nfrom typing import Dict, List, Tuple\n\n\nclass ModuleEnv:\n    def __init__(self, modules: List):\n        self.modules = modules\n        self._state: Dict = {}\n\n    def reset(self) -> Dict:\n        self._state = {}\n        return self._state\n\n    def step(self, actions: Dict) -> Tuple[Dict, Dict, bool, Dict]:\n        """\n        Apply actions to modules, advance state.\n\n        Returns: next_state, rewards, done, info\n        """\n        # TODO: apply actions to respective module MARL hooks\n        # TODO: run modules, compute rewards\n        next_state = self._state.copy()\n        rewards = {k: 0.0 for k in actions}\n        done = False\n        info = {}\n        return next_state, rewards, done, info\n', 'src/nosso_mar/training/__init__.py': '', 'src/nosso_mar/training/trainer.py': '"""Simple supervised trainer skeleton for PIMR-NO models."""\nfrom typing import Dict, List\n\n\nclass Trainer:\n    def __init__(self, model, dataloader, cfg: Dict):\n        self.model = model\n        self.dataloader = dataloader\n        self.cfg = cfg\n        self.history: List[Dict] = []\n\n    def train(self, epochs: int = 1) -> List[Dict]:\n        for epoch in range(epochs):\n            epoch_loss = 0.0\n            for batch in self.dataloader:\n                # TODO: forward pass, compute loss, backward, optimizer step\n                pass\n            self.history.append({"epoch": epoch, "loss": epoch_loss})\n        return self.history\n', 'src/nosso_mar/training/losses.py': '"""Loss functions for PIMR-NO training."""\nimport torch\n\n\ndef supervised_mse(prediction, target):\n    """Mean squared error loss."""\n    return torch.mean((prediction - target) ** 2)\n\n\ndef relative_l2(prediction, target):\n    """Relative L2 loss — standard in neural operator literature."""\n    diff_norm = torch.norm(prediction - target, p=2)\n    target_norm = torch.norm(target, p=2)\n    return diff_norm / (target_norm + 1e-8)\n\n\ndef physics_residual_loss(state, pde_fn, weight: float = 1.0):\n    """Physics-informed residual. pde_fn: state -> residual field."""\n    residual = pde_fn(state)\n    return weight * torch.mean(residual ** 2)\n', 'src/nosso_mar/training/marl_trainer.py': '"""MARL trainer skeleton that interfaces with the NOSSO-MAR ModuleEnv."""\nfrom typing import List\n\n\nclass MARLTrainer:\n    def __init__(self, env, agents: List, cfg: dict):\n        self.env = env\n        self.agents = agents\n        self.cfg = cfg\n\n    def run_episode(self):\n        state = self.env.reset()\n        done = False\n        episode_rewards = {a.agent_id: 0.0 for a in self.agents}\n        while not done:\n            actions = {a.agent_id: a.act() for a in self.agents}\n            next_state, rewards, done, info = self.env.step(actions)\n            for a in self.agents:\n                a.update(rewards.get(a.agent_id, 0.0), next_state)\n                episode_rewards[a.agent_id] += rewards.get(a.agent_id, 0.0)\n            state = next_state\n        return episode_rewards\n\n    def train(self, n_episodes: int = 100):\n        history = []\n        for ep in range(n_episodes):\n            rewards = self.run_episode()\n            history.append({"episode": ep, "rewards": rewards})\n        return history\n', 'src/nosso_mar/data/__init__.py': '', 'src/nosso_mar/data/dummy_data_generators.py': '"""Dummy dataset generator for quick local testing."""\nimport numpy as np\nimport xarray as xr\n\n\ndef generate_dummy_bathy(nx: int = 64, ny: int = 64) -> xr.DataArray:\n    x = np.linspace(0, 1, nx)\n    y = np.linspace(0, 1, ny)\n    xx, yy = np.meshgrid(x, y)\n    z = np.sin(2 * np.pi * yy) + np.cos(2 * np.pi * xx)\n    return xr.DataArray(z, coords={"y": y, "x": x}, dims=("y", "x"),\n                        name="bathymetry", attrs={"units": "m"})\n\n\ndef generate_dummy_wave_field(nx: int = 64, ny: int = 64, nt: int = 20) -> xr.DataArray:\n    x = np.linspace(0, 1, nx)\n    y = np.linspace(0, 1, ny)\n    t = np.linspace(0, 10, nt)\n    eta = np.random.randn(nt, ny, nx).astype(np.float32)\n    return xr.DataArray(eta, coords={"t": t, "y": y, "x": x},\n                        dims=("t", "y", "x"), name="wave_field", attrs={"units": "m"})\n\n\nif __name__ == "__main__":\n    b = generate_dummy_bathy()\n    w = generate_dummy_wave_field()\n    print("bathymetry shape:", b.shape)\n    print("wave_field shape:", w.shape)\n', 'src/nosso_mar/utils/__init__.py': '', 'src/nosso_mar/utils/seed.py': '"""Global seed management for reproducibility."""\nimport random\nimport numpy as np\n\n\ndef set_seed(seed: int = 42):\n    random.seed(seed)\n    np.random.seed(seed)\n    try:\n        import torch\n        torch.manual_seed(seed)\n        if torch.cuda.is_available():\n            torch.cuda.manual_seed_all(seed)\n    except ImportError:\n        pass\n    print(f"Global seed set to {seed}")\n', 'src/nosso_mar/utils/metrics.py': '"""Evaluation metrics for NOSSO-MAR."""\nimport numpy as np\n\n\ndef rmse(a: np.ndarray, b: np.ndarray) -> float:\n    a, b = np.asarray(a), np.asarray(b)\n    return float(np.sqrt(((a - b) ** 2).mean()))\n\n\ndef mae(a: np.ndarray, b: np.ndarray) -> float:\n    a, b = np.asarray(a), np.asarray(b)\n    return float(np.abs(a - b).mean())\n\n\ndef relative_l2(a: np.ndarray, b: np.ndarray) -> float:\n    diff = np.linalg.norm(a - b)\n    ref = np.linalg.norm(b)\n    return float(diff / (ref + 1e-10))\n\n\ndef r2_score(a: np.ndarray, b: np.ndarray) -> float:\n    ss_res = ((b - a) ** 2).sum()\n    ss_tot = ((b - b.mean()) ** 2).sum()\n    return float(1 - ss_res / (ss_tot + 1e-10))\n', 'src/nosso_mar/utils/checkpoint.py': '"""Checkpointing utilities for models and scenario states."""\nimport pickle\nfrom pathlib import Path\n\n\ndef save_checkpoint(path: str, obj) -> None:\n    p = Path(path)\n    p.parent.mkdir(parents=True, exist_ok=True)\n    with open(p, "wb") as f:\n        pickle.dump(obj, f)\n    print(f"Checkpoint saved: {p}")\n\n\ndef load_checkpoint(path: str):\n    with open(path, "rb") as f:\n        obj = pickle.load(f)\n    print(f"Checkpoint loaded: {path}")\n    return obj\n\n\ndef save_torch_checkpoint(path: str, model, optimizer=None, epoch: int = 0) -> None:\n    try:\n        import torch\n        p = Path(path)\n        p.parent.mkdir(parents=True, exist_ok=True)\n        payload = {"epoch": epoch, "model_state_dict": model.state_dict()}\n        if optimizer is not None:\n            payload["optimizer_state_dict"] = optimizer.state_dict()\n        torch.save(payload, p)\n        print(f"Torch checkpoint saved: {p}")\n    except ImportError:\n        save_checkpoint(path, {"epoch": epoch})\n', 'scripts/train.py': '#!/usr/bin/env python3\n"""Entry script: train a PIMR-NO model."""\nimport argparse\nfrom pathlib import Path\nimport yaml\n\n\ndef main():\n    parser = argparse.ArgumentParser()\n    parser.add_argument("--config", default="configs/phase1_wave_nearfield_fsi.yaml")\n    args = parser.parse_args()\n\n    cfg = yaml.safe_load(Path(args.config).read_text(encoding="utf-8"))\n    print("Training with config:", cfg.get("scenario", {}).get("name"))\n    # TODO: instantiate dataset, model, trainer and call trainer.train()\n\n\nif __name__ == "__main__":\n    main()\n', 'scripts/train_marl.py': '#!/usr/bin/env python3\n"""Entry script: train MARL agents using PIMR-NO environment."""\nimport argparse\nfrom pathlib import Path\nimport yaml\n\n\ndef main():\n    parser = argparse.ArgumentParser()\n    parser.add_argument("--config", default="configs/marl_agents.yaml")\n    args = parser.parse_args()\n\n    cfg = yaml.safe_load(Path(args.config).read_text(encoding="utf-8"))\n    print("MARL training with algorithm:", cfg.get("marl", {}).get("algorithm"))\n    # TODO: instantiate ModuleEnv, agents, MARLTrainer and call trainer.train()\n\n\nif __name__ == "__main__":\n    main()\n', 'scripts/run_scenario.py': '#!/usr/bin/env python3\n"""Run a scenario using the ScenarioEngine."""\nimport argparse\n\n\ndef main():\n    parser = argparse.ArgumentParser()\n    parser.add_argument("--config", default="configs/default.yaml")\n    args = parser.parse_args()\n\n    from src.nosso_mar.core.scenario_engine import ScenarioEngine\n    engine = ScenarioEngine(args.config)\n    engine.run()\n\n\nif __name__ == "__main__":\n    main()\n', 'tests/__init__.py': '', 'tests/test_core.py': '"""Tests for core infrastructure (ScenarioEngine, CouplingManager, FieldSchema)."""\nfrom pathlib import Path\nimport yaml\nimport tempfile\n\n\ndef test_scenario_engine_loads():\n    from src.nosso_mar.core.scenario_engine import ScenarioEngine\n    cfg = {"scenario": {"name": "test"}, "modules": {}}\n    with tempfile.NamedTemporaryFile(mode="w", suffix=".yaml", delete=False) as f:\n        yaml.dump(cfg, f)\n        tmp = f.name\n    engine = ScenarioEngine(tmp)\n    assert engine.summary()["scenario"] == "test"\n    Path(tmp).unlink()\n\n\ndef test_coupling_manager_sequential():\n    from src.nosso_mar.core.coupling_manager import CouplingManager\n\n    class DummyModule:\n        def run(self, inputs):\n            inputs["flag"] = True\n            return inputs\n\n    cm = CouplingManager({})\n    result = cm.execute_sequential([DummyModule()], {})\n    assert result["flag"] is True\n', 'tests/test_phase1.py': '"""Tests for Phase 1 NearFieldFSIModule."""\n\n\ndef test_phase1_module_runs():\n    from src.nosso_mar.modules.phase1_nearfield_fsi import NearFieldFSIModule\n    module = NearFieldFSIModule({"operator": {}})\n    out = module.run({"wave_field": None})\n    assert isinstance(out, dict)\n    assert "forces" in out\n\n\ndef test_phase1_observation():\n    from src.nosso_mar.modules.phase1_nearfield_fsi import NearFieldFSIModule\n    module = NearFieldFSIModule({})\n    obs = module.get_observation("wec_agent_1")\n    assert isinstance(obs, dict)\n', 'tests/test_phase6.py': '"""Tests for Phase 6 AdvancedFSIModule."""\n\n\ndef test_phase6_module_runs():\n    from src.nosso_mar.modules.phase6_advanced_fsi import AdvancedFSIModule\n    module = AdvancedFSIModule({})\n    out = module.run({})\n    assert isinstance(out, dict)\n', 'notebooks/demo.md': '# Demo Notebook\n\nOpen Jupyter and use the cells below to test the NOSSO-MAR scaffold.\n\n## 1. Load config\n\n```python\nimport yaml\nfrom pathlib import Path\ncfg = yaml.safe_load(Path("configs/phase1_wave_nearfield_fsi.yaml").read_text())\nprint(cfg)\n```\n\n## 2. Generate dummy data\n\n```python\nfrom src.nosso_mar.data.dummy_data_generators import generate_dummy_bathy, generate_dummy_wave_field\nbathy = generate_dummy_bathy()\nwave = generate_dummy_wave_field()\nprint(bathy)\nprint(wave)\n```\n\n## 3. Run Phase 1 module\n\n```python\nfrom src.nosso_mar.modules.phase1_nearfield_fsi import NearFieldFSIModule\nmodule = NearFieldFSIModule(cfg.get("modules", {}).get("phase1_nearfield_fsi", {}))\nout = module.run({"wave_field": wave, "bathymetry": bathy})\nprint(out)\n```\n'}


# ---------------------------------------------------------------
# Create files on disk
# ---------------------------------------------------------------

def create_repo() -> None:
    print(f"\nCreating NOSSO-MAR scaffold at: {BASE_DIR}\n")
    for rel_path, content in FILE_MAP.items():
        target = BASE_DIR / rel_path
        write_text(target, content)
        print(f"  wrote: {rel_path}")

    if INITIALIZE_GIT:
        run_cmd(["git", "init"])
        run_cmd(["git", "checkout", "-b", "main"])
        run_cmd(["git", "add", "."])
        run_cmd(["git", "commit", "-m", "Initial scaffolding for NOSSO-MAR (Phases 0..7)"])
        print("\nGit repository initialized and initial commit created.")


def maybe_push_github() -> None:
    if not PUSH_TO_GITHUB:
        return
    if not (GITHUB_USER and GITHUB_TOKEN):
        print("ERROR: GITHUB_USER and GITHUB_TOKEN must be set to push to GitHub.")
        return

    print("\nCreating GitHub repository via API...")
    payload = json.dumps({
        "name": GITHUB_REPO,
        "private": PRIVATE_REPO,
        "description": "NOSSO-MAR scaffold (PIMR-NO + MARL) - autogenerated",
    }).encode("utf-8")
    req = urllib.request.Request(
        "https://api.github.com/user/repos",
        data=payload,
        headers={
            "Authorization": f"token {GITHUB_TOKEN}",
            "Content-Type": "application/json",
            "User-Agent": "nosso-mar-scaffolder",
        },
    )
    try:
        with urllib.request.urlopen(req) as r:
            print("GitHub repo created:", json.loads(r.read().decode()).get("html_url"))
        remote_url = f"https://{GITHUB_USER}:{GITHUB_TOKEN}@github.com/{GITHUB_USER}/{GITHUB_REPO}.git"
        run_cmd(["git", "remote", "add", "origin", remote_url])
        run_cmd(["git", "push", "-u", "origin", "main"])
        print(f"Repository pushed to https://github.com/{GITHUB_USER}/{GITHUB_REPO}")
    except urllib.error.HTTPError as e:
        print("GitHub API error:", e.read().decode())


if __name__ == "__main__":
    create_repo()
    maybe_push_github()
    print("\nNOSSO-MAR scaffolding complete.")
    print("Next steps:")
    print(f"  cd {BASE_DIR}")
    print("  conda env create -f environment.yml && conda activate nosso-mar")
    print("  pre-commit install")
    print("  git checkout -b develop")
    print("  python scripts/run_scenario.py --config configs/phase1_wave_nearfield_fsi.yaml")
